rules.cssText:
@media (hover: hover) and (pointer: fine) {
  [data-hover-features="clickable"]:hover [data-hover-features="arrow"] { transform: translateX(6px); }
  [data-hover-features="clickable"]:hover [data-hover-features="text"], [data-hover-features="clickable"]:hover [data-hover-features="arrow"] { color: var(--colors--primary-accent); }
  [data-hover-features="clickable"]:hover [data-hover-features="border"] { background-color: var(--colors--primary-accent) !important; }
  [data-hover-features="clickable"]:hover + [data-hover-features="item-content"] { opacity: 1; pointer-events: auto; }
